var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"눈 안이 가려워, 눈 안이 가려워, 눈 안이 가려워, 눈 안이 가려워, 가려워, 가려워, 가려워…….","JPN":"目がかゆい、目がかゆい、メがかゆい、メガカユイ、カユイ、カユイ、カユイ……","ENG":"It's getting itchy behind my eyeball… So itchy… itchy, itchy, itchy, itchy, itchy…","TWN":"眼睛好癢，眼睛好癢，眼睛好癢，好癢好癢，好癢好癢……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"너, 넌 죽었잖아! 다가오지 마, 다가오지 마……!","JPN":"お、お前は死んだはずだ！　ち、近寄るな……！","ENG":"B-but you're dead! Stay back! Go away!","TWN":"你…你不是死掉了嗎？不要過來，走開……！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"죽이라고요? 누굴? 누굴 죽이면 돼요? 죽이면 제 귀에 그만 속삭일 거죠? 네?","JPN":"殺せって？　誰を？　誰を殺せばいいんですか？　殺したら私の耳元でささやくのをやめてくれますよね？　ね？","ENG":"Kill them? Who? Who should I kill? Will you stop whispering in my ears if I kill them? Please?","TWN":"殺人嗎？要殺誰？要我殺誰？殺掉他你就不會再在我耳邊吵了吧？是嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>잔여 동력 1.5%. 기동을 중단하고 즉각 동력을 공급해야 합니다.</color>","JPN":"<color=#ff3636>残余エネルギー1.5％。起動を中断し、直ちに動力を供給してください。</color>","ENG":"<color=#ff3636>Current remaining power is at 1.5%. Suspend all activity and immediately supply more power.</color>","TWN":"<color=#ff3636>剩餘動能 1.5%。暫停運作，請立刻補充動能。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"잔류 직원들에게서 침식 증후군 증세 확인.","JPN":"残留社員から侵食症候群の症状を確認。","ENG":"Corruption Syndrome detected in remaining staff.","TWN":"發現剩下的員工有侵蝕症候群的症狀。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"건물 내부의 침식파 농도가 급격히 상승한 것이 원인으로 추정됩니다.","JPN":"建物内部の侵食波濃度が急激に上昇したことが原因と推定されます。","ENG":"Analysis suggests the sudden spike in Corruption Ray levels in the building is the cause.","TWN":"推測是空間內侵蝕波濃度突然激增導致。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……엘리자베스가 언급했던 아티팩트의 영향으로 추정되는군요.","JPN":"……エリザベスが言及したアーティファクトの影響と推定されます。","ENG":"…This may be the effect of the artifact Elizabeth mentioned.","TWN":"……看來是受到伊莉莎白說過的那個人造神器的影響。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래, 호라이즌. 전부 너 때문에 벌어진 일이지.","JPN":"そうだよ、ホライズン。全部貴様のせいで起こったことだ。","ENG":"That's right, Horizon. This is happening all because of you.","TWN":"沒錯，地平線，這些事都是因你而起！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"너라는 바퀴벌레 한 마리가 들어와서 집안을 한바탕 뒤엎는 거 아니겠나?","JPN":"貴様というゴキブリが一匹入ってきやがって、家中を荒らしていることはわかってるよな？","ENG":"When a roach like you crawls into the house, I'm forced to fumigate the entire place.","TWN":"因為你一隻蟑螂闖進家裡，就把家裡搞得天翻地覆的！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"윌버. 돈은 준비해 뒀습니까.","JPN":"ウィルバー、金の用意はできていますか。","ENG":"Wilbur. Have you prepared the money?","TWN":"韋爾伯，錢都準備好了嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"돈? 내가?","JPN":"金？　僕が？","ENG":"Money? Me?","TWN":"我？什麼錢？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"너한테 왜?","JPN":"なぜ貴様に？","ENG":"Why should I?","TWN":"為什麼要給你錢？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신이 제 것을 가져갔기 때문이죠. 다른 이유가 더 필요합니까.","JPN":"あなたが私の物を持っていったからです。他に理由が必要ですか？","ENG":"Because you took what is mine. Why else?","TWN":"因為你拿走了我的東西，還有需要其他原因嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"……호라이즌. 이 무식한 사채꾼 같으니라고.","JPN":"……ホライズン。この無知な金の亡者が。","ENG":"Oh, Horizon. You stupid little loan shark.","TWN":"……地平線，你這個愚蠢的高利貸！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"대학원생 윌버 웨이틀리는 오래 전에 실종 처리 됐어.","JPN":"大学院の卒業生、ウィルバー・ウェイトリーはずいぶん前に失踪したことになっている。","ENG":"The grad school student Wilbur Whateley has long been declared missing.","TWN":"大學生韋爾伯·韋特利，很久以前就已經是失蹤人口了。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그리고 제프티 바이오테크의 대표 <color=#ffd34c>딘 코너</color>는, 너한테 단 한 푼도 빌린 적 없지.","JPN":"そしてジェフティ・バイオテック代表<color=#ffd34c>ディーン・コナー</color>は、貴様から1クレジットも借りたことがない。","ENG":"Whereas Jehuty Biotech's CEO <color=#ffd34c>Dean Conner</color> hasn't borrowed a penny from you.","TWN":"而傑夫堤生物科技的代表<color=#ffd34c>狄恩•康納</color>，可是一毛錢都沒跟你借過！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"멀쩡히 살아 있지 않습니까. 윌버.","JPN":"元気に生きているじゃないですか、ウィルバー。","ENG":"But you're alive and well, Wilbur.","TWN":"韋爾伯，你還活著不是嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};